export type Cell = [number, number];

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const areNeighbors = ([x, y]: Cell, [nx, ny]: Cell): boolean =>
  (x !== nx || y !== ny) && Math.abs(nx - x) <= 1 && Math.abs(ny - y) <= 1;

const countLiveNeighbors = (cell: Cell, cells: Cell[]): number =>
  cells.filter((other) => areNeighbors(cell, other)).length;

const neighborhoodOf = ([x, y]: Cell): Cell[] => {
  const cells: Cell[] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      cells.push([x + dx, y + dy]);
    }
  }
  return cells;
};

const uniqueCells = (cells: Cell[]): Cell[] => {
  const seen = new Set<string>();
  return cells.filter((cell) => {
    const key = cellKey(cell);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
};

const survives = (liveNeighbors: number, alive: boolean): boolean =>
  liveNeighbors === 3 || (liveNeighbors === 2 && alive);

export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(cellKey));
  const candidates = uniqueCells(cells.flatMap(neighborhoodOf));
  return candidates.filter((cell) =>
    survives(countLiveNeighbors(cell, cells), aliveKeys.has(cellKey(cell)))
  );
}
